   341→bool closest_intersection(vec3 start, vec3 dir, const vector<Triangle>& triangles, Intersection& cloestIntersection, Intersection& mirIntersection, int light)
   342→{
   343→
   344→    bool flag = false;
   345→    float min = 0.0;
