   348→    vec3 reflect_position, reflect_dir;
   349→    mat3 A;
   350→    vec3 front_triangle_v0, front_triangle_v1, front_triangle_v2;
   351→    front_triangle_v0 = vec3(-0.76f, -0.87f, -1.0f);
