   354→    Intersection reflect_intersec;
   355→
   356→    float t_front, u_front, v_front;
   357→    if (RayTriangleIntersection(start, dir, front_triangle_v0, front_triangle_v1, front_triangle_v2, t_front, u_front, v_front))
   358→        ignore = 0;
   359→
   360→    for (size_t i = 0; i < triangles.size(); i++)
   361→    {
   362→        v0 = triangles[i].v0;
   363→        v1 = triangles[i].v1;
   364→        v2 = triangles[i].v2;
   365→
   366→        e1 = v1 - v0;
   367→        e2 = v2 - v0;
   368→        b = start - v0;
   369→
   370→        if (ignore == 1 && light == 0)
