   405→        }
   406→        else if (ignore == 0 || light == 1)
   407→        {
   408→            float t_hit, u_hit, v_hit;
   409→            if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   410→            {
   411→                if (!flag)
   412→                {
   413→                    min = t_hit;
