   550→bool mirror_intersection(vec3 start, vec3 dir, const vector<Triangle>& triangles, Intersection& cloestIntersection)
   551→{
   552→    bool flag = false;
   553→    float min = 0.0;
   554→    int triangle_index;
   555→    vec3 v0, v1, v2, e1, e2, b, x, intersection_pos, e1_, e2_, b_, shadow_colour;
   556→    mat3 A;
   557→
   558→    for (size_t i = 0; i < triangles.size(); i++)
   559→    {
   560→        v0 = triangles[i].v0;
   561→        v1 = triangles[i].v1;
   562→        v2 = triangles[i].v2;
   563→
   564→        float t_hit, u_hit, v_hit;
   565→        if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   566→        {
   567→            if (!flag)
   568→            {
   569→                min = t_hit;
