    58→inline bool RayTriangleIntersection(const vec3& orig,
    59→                                    const vec3& dir,
    60→                                    const vec3& v0,
    61→                                    const vec3& v1,
    62→                                    const vec3& v2,
    63→                                    float& t,
    64→                                    float& u,
    65→                                    float& v)
    66→{
    67→    const float EPSILON = 1e-6f;
    68→    vec3 e1 = v1 - v0;
    69→    vec3 e2 = v2 - v0;
    70→    vec3 pvec = glm::cross(dir, e2);
    71→    float det = glm::dot(e1, pvec);
    72→    if (fabs(det) < EPSILON)
    73→        return false;
    74→
    75→    float invDet = 1.0f / det;
    76→    vec3 tvec = orig - v0;
    77→    u = glm::dot(tvec, pvec) * invDet;
    78→    if (u < 0.0f || u > 1.0f)
    79→        return false;
    80→
    81→    vec3 qvec = glm::cross(tvec, e1);
    82→    v = glm::dot(dir, qvec) * invDet;
    83→    if (v < 0.0f || u + v > 1.0f)
    84→        return false;
    85→
    86→    t = glm::dot(e2, qvec) * invDet;
    87→    return t > 0.0f;
    88→}
