    96→bool ClosestIntersection(vec3 start, vec3 dir, const vector<Triangle>& triangles, Intersection& cloestIntersection) {
    97→	bool flag = false;
    98→	float min = 0.0;
    99→	int triangleIndex;
   100→	for (int i = 0; i < triangles.size(); i++) {
   101→		vec3 v0 = triangles[i].v0;
   102→		vec3 v1 = triangles[i].v1;
   103→		vec3 v2 = triangles[i].v2;
   104→
   105→		vec3 e1 = v1 - v0;
   106→		vec3 e2 = v2 - v0;
   107→		vec3 b = start - v0;
   108→
   109→		mat3 A(-dir, e1, e2);
   110→		vec3 x = glm::inverse(A) * b;
   111→
   112→		if (x[1] > 0 && x[2] > 0 && (x[1] + x[2]) < 1 && x[0] > 0) {
   113→			if (!flag) {
   114→				min = x[0];
   115→				triangleIndex = i;
   116→			}
   117→			flag = true;
   118→			if (min > x[0]) {
   119→				min = x[0];
   120→				triangleIndex = i;
   121→			}
   122→
   123→		}
   124→
   125→	}
   126→
   127→	cloestIntersection.position = dir;
   128→	cloestIntersection.distance = min;
   129→	cloestIntersection.triangleIndex = triangleIndex;
   130→}

