     9→// Used to describe a triangular surface:
    10→class Triangle
    11→{
    12→public:
    13→	glm::vec3 v0;
    14→	glm::vec3 v1;
    15→	glm::vec3 v2;
    16→	glm::vec3 normal;
    17→	glm::vec3 color;
    18→
    19→	Triangle( glm::vec3 v0, glm::vec3 v1, glm::vec3 v2, glm::vec3 color )
    20→		: v0(v0), v1(v1), v2(v2), color(color)
    21→	{
    22→		ComputeNormal();
    23→	}
    24→
    25→	void ComputeNormal()
    26→	{
    27→		glm::vec3 e1 = v1 - v0;
    28→		glm::vec3 e2 = v2 - v0;
    29→		normal = glm::normalize( glm::cross( e2, e1 ) );
    30→	}
    31→};
