    55→
    56→	float L = 555;			// Length of Cornell Box side.
    57→
    58→	vec3 A(L, 0, 0);
    59→	vec3 B(0, 0, 0);
    60→	vec3 C(L, 0, L);
    61→	vec3 D(0, 0, L);
    62→
    63→	vec3 E(L, L, 0);
