   114→void Interpolate( vec3 a, vec3 b, vector<vec3>& result )
   115→{
   116→    for (size_t i = 0;  i < result.size(); i++)
   117→    {
   118→        result[i].x = (a.x + (b.x - a.x) / result.size() * i);
   119→        result[i].y = (a.y + (b.y - a.y) / result.size() * i);
   120→        result[i].z = (a.z + (b.z - a.z) / result.size() * i);
   121→    }
   122→
   123→}

